const part = $input.first().json.candidates[0].content.parts[0];
const pcm = Buffer.from(part.inlineData.data, 'base64');

const sampleRate = 24000;
const numChannels = 1;
const bitsPerSample = 16;
const byteRate = sampleRate * numChannels * bitsPerSample / 8;
const blockAlign = numChannels * bitsPerSample / 8;

const header = Buffer.alloc(44);
header.write('RIFF', 0);
header.writeUInt32LE(36 + pcm.length, 4);
header.write('WAVE', 8);
header.write('fmt ', 12);
header.writeUInt32LE(16, 16);
header.writeUInt16LE(1, 20);               // PCM format
header.writeUInt16LE(numChannels, 22);
header.writeUInt32LE(sampleRate, 24);
header.writeUInt32LE(byteRate, 28);
header.writeUInt16LE(blockAlign, 32);
header.writeUInt16LE(bitsPerSample, 34);
header.write('data', 36);
header.writeUInt32LE(pcm.length, 40);

const wav = Buffer.concat([header, pcm]);

const uniqueFileName = `speech_${Date.now()}.wav`;
const binary = await this.helpers.prepareBinaryData(wav, uniqueFileName, 'audio/wav');
return [{ json: {}, binary: { audio: binary } }];

const raw = $input.first().json.content.parts[0].text;
const cleaned = raw.replace(/^```json\s*/, '').replace(/\s*```$/, '').trim();
const analysisJson = JSON.parse(cleaned);
const wm = JSON.parse($('Get Working Memory').first().json.value);

return [{
  json: {
    track_id: wm.track_id,
    chunk_id: wm.chunk_id,
    quality_score: analysisJson.score,
    ai_feedback_json: analysisJson,
    transcript_or_notes: analysisJson.transcription,
  }
}];
